# Description: Lister les fichiers du bureau avec leur taille en MB

import os
from pathlib import Path

def list_desktop_files():
    try:
        desktop = Path.home() / "Desktop"
        if not desktop.exists():
            print(f"Le répertoire {desktop} n'existe pas.")
            return
        files = [f for f in desktop.iterdir() if f.is_file()]
        if not files:
            print("Aucun fichier trouvé sur le bureau.")
            return
        print(f"Fichiers dans {desktop}:")
        for file in files:
            try:
                size_bytes = file.stat().st_size
                size_mb = size_bytes / (1024 * 1024)
                print(f"{file.name:40} : {size_mb:.2f} MB")
            except Exception as e:
                print(f"Erreur lors de la lecture de {file.name}: {e}")
    except Exception as e:
        print(f"Erreur inattendue: {e}")

if __name__ == "__main__":
    list_desktop_files()